// Text chunken: ~500 Token, 50 Token Overlap
// Einfache Implementierung via Zeichenanzahl (ca. 1 Token ≈ 4 Zeichen)
const text = $input.first().json.text || $input.first().binary?.data?.toString('utf8') || '';
const chunkSize = 2000;  // ~500 Token
const overlap = 200;     // ~50 Token

const chunks = [];
let start = 0;
let chunkIndex = 0;

while (start < text.length) {
  const end = Math.min(start + chunkSize, text.length);
  const chunk = text.slice(start, end);

  if (chunk.trim().length > 50) {  // Leere/kurze Chunks überspringen
    chunks.push({
      json: {
        chunkIndex,
        text: chunk.trim(),
        tokenCount: Math.round(chunk.length / 4),
        documentId: $('Webhook: Ingest Document').first().json.document_id,
        metadata: {
          sourceUri: $('Webhook: Ingest Document').first().json.source_uri,
          chunkStart: start,
          chunkEnd: end
        }
      }
    });
    chunkIndex++;
  }

  start = end - overlap;
}

return chunks;
